class Solution {
    public int maximumWealth(int[][] accounts) {
        int[] sums = new int[accounts.length];

        for (int i = 0; i < accounts.length; i++) {
            int rowSum = 0;
            for (int j = 0; j < accounts[i].length; j++) {
                rowSum += accounts[i][j];
            }
            sums[i] = rowSum;
        }

        int max = sums[0];
        for (int i = 1; i < sums.length; i++) {
            if (sums[i] > max) {
                max = sums[i];
            }
        }
        return max;
    }
}

class Solution {
    public int maximumWealth(int[][] accounts) {
        int maxWealth = 0;

        for (int[] customer : accounts) {
            int wealth = 0;
            for (int money : customer) {
                wealth += money;
            }
            maxWealth = Math.max(maxWealth, wealth);
        }
        return maxWealth;
    }
}

class Solution {
    public int[] shuffle(int[] nums, int n) {
        int[] x = new int[n];
        int[] y = new int[n];
        for (int i = 0; i < n; i++) {
            x[i] = nums[i];
            y[i] = nums[i + n];
        }

        int[] result = new int[2 * n];
        for (int i = 0; i < n; i++) {
            result[2 * i] = x[i];
            result[2 * i + 1] = y[i];
        }
        return result;
    }
}

