        }
        return result;
    }
}

class Solution {
    public int findNumbers(int[] nums) {
        int count = 0;
        for (int num : nums) {
            String s = String.valueOf(num);
            if (s.length() % 2 == 0) {
                count++;
            }
        }
        return count;
    }
}

class Solution {
    public int findNumbers(int[] nums) {
        int count = 0;
        for (int num : nums) {
            int digits = 0;
            while (num > 0) {
                digits++;
                num /= 10;
            }
            if (digits % 2 == 0) {
                count++;
            }
        }
        return count;
    }
}

class Solution {
    public int findMaxConsecutiveOnes(int[] nums) {
        int maxCount = 0;
        for (int i = 0; i < nums.length; i++) {
            if (nums[i] == 1) {
                int j = i;
                while (j < nums.length && nums[j] == 1) {
                    j++;
                }
                maxCount = Math.max(maxCount, j - i);
            }
        }
        return maxCount;
    }
}

class Solution {
    public int findMaxConsecutiveOnes(int[] nums) {
        int maxCount = 0;
        int currentStreak = 0;

        for (int num : nums) {
            if (num == 1) {
                currentStreak++;
                maxCount = Math.max(maxCount, currentStreak);
            } else {
                currentStreak = 0;
            }
        }
        return maxCount;
    }
}

